import os
import re
import time
import uuid
from flask import Blueprint, render_template, request, jsonify, send_file, current_app
from models import db, Screenshot

webscreen_bp = Blueprint("webscreen", __name__, url_prefix="/webscreen")

def capture_screenshot(url, width, height):
    try:
        from playwright.sync_api import sync_playwright
        filename = f"screenshot_{uuid.uuid4().hex[:8]}.png"
        out_path = os.path.join(current_app.config["SCREENSHOT_FOLDER"], filename)
        with sync_playwright() as p:
            browser = p.chromium.launch(args=["--no-sandbox", "--disable-setuid-sandbox"])
            page = browser.new_page(viewport={"width": int(width), "height": int(height)})
            page.goto(url, wait_until="networkidle", timeout=30000)
            page.screenshot(path=out_path, full_page=True)
            browser.close()
        return filename, None
    except Exception as e:
        return None, str(e)

@webscreen_bp.route("/")
def index():
    shots = Screenshot.query.order_by(Screenshot.created_at.desc()).limit(12).all()
    return render_template("webscreen/index.html", shots=shots)

@webscreen_bp.route("/capture", methods=["POST"])
def capture():
    data = request.get_json()
    url = data.get("url", "").strip()
    width = data.get("width", 1280)
    height = data.get("height", 800)

    if not url:
        return jsonify({"error": "URL is required"}), 400

    if not url.startswith(("http://", "https://")):
        url = "https://" + url

    filename, error = capture_screenshot(url, width, height)
    if error:
        return jsonify({"error": f"Screenshot failed: {error}"}), 500

    shot = Screenshot(url=url, filename=filename)
    db.session.add(shot)
    db.session.commit()

    return jsonify({
        "success": True,
        "filename": filename,
        "url": f"/static/screenshots/{filename}",
        "id": shot.id
    })

@webscreen_bp.route("/download/<filename>")
def download(filename):
    path = os.path.join(current_app.config["SCREENSHOT_FOLDER"], filename)
    return send_file(path, as_attachment=True, download_name=filename)

@webscreen_bp.route("/delete/<int:shot_id>", methods=["DELETE"])
def delete(shot_id):
    shot = Screenshot.query.get_or_404(shot_id)
    try:
        path = os.path.join(current_app.config["SCREENSHOT_FOLDER"], shot.filename)
        if os.path.exists(path):
            os.remove(path)
    except:
        pass
    db.session.delete(shot)
    db.session.commit()
    return jsonify({"success": True})

:root {
  --bg: #0f0f0f;
  --surface: #1a1a1a;
  --surface2: #242424;
  --border: #2e2e2e;
  --accent: #6c63ff;
  --accent2: #ff6584;
  --text: #f0f0f0;
  --text-muted: #888;
  --success: #22c55e;
  --warning: #f59e0b;
  --danger: #ef4444;
  --radius: 16px;
  --radius-sm: 10px;
  --shadow: 0 4px 24px rgba(0,0,0,0.4);
}

* { box-sizing: border-box; margin: 0; padding: 0; }

body {
  background: #080808;
  min-height: 100vh;
  display: flex;
  align-items: flex-start;
  justify-content: center;
  padding: 0;
  font-family: -apple-system, BlinkMacSystemFont, 'SF Pro Display', 'Segoe UI', sans-serif;
  color: var(--text);
}

/* Phone Shell */
.phone-shell {
  width: 100%;
  max-width: 430px;
  min-height: 100vh;
  background: var(--bg);
  display: flex;
  flex-direction: column;
  position: relative;
  overflow: hidden;
}

@media (min-width: 500px) {
  body { align-items: center; padding: 20px 0; background: #050505; }
  .phone-shell {
    min-height: calc(100vh - 40px);
    max-height: 900px;
    border-radius: 44px;
    box-shadow: 0 0 0 1px #333, 0 30px 80px rgba(0,0,0,0.8), inset 0 0 0 1px #1a1a1a;
    overflow: hidden;
  }
}

/* Status Bar */
.status-bar {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 12px 24px 4px;
  font-size: 12px;
  font-weight: 600;
  color: var(--text);
  flex-shrink: 0;
}
.status-bar .icons { display: flex; gap: 6px; }

/* Header */
.app-header {
  flex-shrink: 0;
  padding: 8px 20px 12px;
  background: var(--bg);
  border-bottom: 1px solid var(--border);
}
.header-inner {
  display: flex;
  align-items: center;
  gap: 12px;
}
.header-title {
  font-size: 20px;
  font-weight: 700;
  color: var(--text);
  flex: 1;
}
.back-btn {
  width: 34px; height: 34px;
  border-radius: 50%;
  background: var(--surface2);
  display: flex; align-items: center; justify-content: center;
  color: var(--text); text-decoration: none;
  font-size: 14px;
  flex-shrink: 0;
}
.back-btn:hover { background: var(--border); color: var(--text); }

/* Body */
.app-body {
  flex: 1;
  overflow-y: auto;
  padding: 16px;
  scrollbar-width: none;
}
.app-body::-webkit-scrollbar { display: none; }

/* Bottom Nav */
.bottom-nav {
  display: flex;
  background: var(--surface);
  border-top: 1px solid var(--border);
  padding: 8px 0 calc(8px + env(safe-area-inset-bottom));
  flex-shrink: 0;
}
.nav-item {
  flex: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 3px;
  padding: 4px 0;
  text-decoration: none;
  color: var(--text-muted);
  font-size: 10px;
  font-weight: 500;
  transition: color 0.2s;
}
.nav-item i { font-size: 18px; }
.nav-item.active { color: var(--accent); }
.nav-item:hover { color: var(--text); }

/* Cards */
.card-app {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 16px;
  margin-bottom: 12px;
  transition: transform 0.15s, box-shadow 0.15s;
}
.card-app:hover, .card-app:active { transform: scale(0.98); }

.card-icon {
  width: 48px; height: 48px;
  border-radius: 12px;
  display: flex; align-items: center; justify-content: center;
  font-size: 22px;
  margin-bottom: 10px;
  flex-shrink: 0;
}

/* Inputs */
.input-field {
  width: 100%;
  background: var(--surface2);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  padding: 12px 14px;
  color: var(--text);
  font-size: 15px;
  outline: none;
  transition: border-color 0.2s;
  margin-bottom: 10px;
}
.input-field:focus { border-color: var(--accent); }
.input-field::placeholder { color: var(--text-muted); }
select.input-field option { background: var(--surface2); }

textarea.input-field { resize: none; min-height: 90px; }

/* Buttons */
.btn-primary-app {
  width: 100%;
  background: var(--accent);
  color: #fff;
  border: none;
  border-radius: var(--radius-sm);
  padding: 14px;
  font-size: 15px;
  font-weight: 600;
  cursor: pointer;
