  color: var(--accent);
}
.upload-zone i { font-size: 32px; display: block; margin-bottom: 10px; }

/* Rule row */
.rule-row {
  display: flex;
  gap: 8px;
  align-items: center;
  background: var(--surface2);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  padding: 10px 12px;
  margin-bottom: 8px;
}

/* Markdown content */
.md-content h1, .md-content h2, .md-content h3 { color: var(--accent); margin: 12px 0 6px; font-size: 14px; }
.md-content p { margin-bottom: 8px; font-size: 13px; }
.md-content code { background: var(--surface); padding: 2px 6px; border-radius: 4px; font-size: 12px; color: #f97316; }
.md-content pre { background: var(--surface); padding: 12px; border-radius: 8px; overflow-x: auto; margin: 8px 0; }
.md-content pre code { background: none; padding: 0; color: #86efac; font-size: 12px; }
.md-content ul, .md-content ol { padding-left: 18px; margin-bottom: 8px; font-size: 13px; }
.md-content table { width: 100%; border-collapse: collapse; font-size: 12px; margin: 8px 0; }
.md-content th { background: var(--surface2); padding: 6px 8px; border: 1px solid var(--border); }
.md-content td { padding: 6px 8px; border: 1px solid var(--border); }

/* Signature pad */
.sig-pad {
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  background: #fff;
  cursor: crosshair;
  touch-action: none;
}

/* Screen preview */
.screen-frame {
  background: #000;
  border-radius: 8px;
  overflow: hidden;
  border: 2px solid var(--border);
  position: relative;
}
.screen-frame iframe {
  border: none;
  display: block;
  transform-origin: top left;
  pointer-events: none;
}

/* Admin specific */
.admin-menu-item {
  display: flex;
  align-items: center;
  gap: 14px;
  padding: 14px;
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  color: var(--text);
  text-decoration: none;
  margin-bottom: 10px;
  transition: border-color 0.2s;
}
.admin-menu-item:hover { border-color: var(--accent); color: var(--text); }
.admin-menu-icon {
  width: 40px; height: 40px;
  border-radius: 10px;
  display: flex; align-items: center; justify-content: center;
  font-size: 18px;
  flex-shrink: 0;
}

/* Screenshot thumbnail */
.screenshot-thumb {
  width: 100%;
  aspect-ratio: 16/10;
  object-fit: cover;
  border-radius: 8px;
  background: var(--surface2);
}

{% extends "base.html" %}
{% block title %}File Renamer{% endblock %}
{% block header_title %}File Renamer{% endblock %}
{% set show_back = true %}{% set back_url = '/' %}
{% block header_actions %}
<span style="font-size:11px;color:var(--text-muted);background:var(--surface2);padding:4px 10px;border-radius:20px;">ZIP → Rename</span>
{% endblock %}

{% block content %}
<!-- Upload Zone -->
<div class="upload-zone" id="uploadZone" onclick="document.getElementById('zipInput').click()">
  <i class="fas fa-cloud-upload-alt"></i>
  <div style="font-size:14px;font-weight:600;" id="uploadLabel">Tap to upload ZIP file</div>
  <div style="font-size:12px;margin-top:4px;">Max 50MB</div>
</div>
<input type="file" id="zipInput" accept=".zip" style="display:none" onchange="handleFile(this)">

<!-- Rules -->
<div class="section-title">Rename Rules</div>
<div id="rulesList"></div>

<div style="display:flex;gap:8px;flex-wrap:wrap;margin-bottom:14px;">
  <button class="chip" onclick="addRule('prefix')"><i class="fas fa-plus"></i> Prefix</button>
  <button class="chip" onclick="addRule('suffix')"><i class="fas fa-plus"></i> Suffix</button>
  <button class="chip" onclick="addRule('replace')"><i class="fas fa-plus"></i> Find & Replace</button>
  <button class="chip" onclick="addRule('lowercase')"><i class="fas fa-plus"></i> Lowercase</button>
  <button class="chip" onclick="addRule('uppercase')"><i class="fas fa-plus"></i> Uppercase</button>
  <button class="chip" onclick="addRule('spaces_to_underscores')"><i class="fas fa-plus"></i> Spaces→_</button>
  <button class="chip" onclick="addRule('remove_special')"><i class="fas fa-plus"></i> Remove Special Chars</button>
  <button class="chip" onclick="addRule('numbering')"><i class="fas fa-plus"></i> Auto-Number</button>
</div>

<button class="btn-primary-app" id="renameBtn" onclick="processRename()" disabled>
  <i class="fas fa-tags"></i> Apply Rules & Download
</button>

<!-- Results -->
<div id="resultBox" style="display:none;margin-top:16px;">
  <div class="section-title">Preview</div>
  <div class="card-app" id="previewList" style="max-height:260px;overflow-y:auto;"></div>
</div>

<!-- History -->
{% if jobs %}
<div class="section-title" style="margin-top:20px;">Recent Jobs</div>
<div class="card-app">
  {% for job in jobs %}
  <div class="list-item">
    <i class="fas fa-file" style="color:var(--text-muted);font-size:14px;"></i>
    <div style="flex:1;min-width:0;">
      <div style="font-size:12px;color:var(--text-muted);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">{{ job.original_name }}</div>
      <div style="font-size:13px;font-weight:500;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">{{ job.renamed_to }}</div>
    </div>
  </div>
  {% endfor %}
</div>
{% endif %}
{% endblock %}

{% block scripts %}
<script>
let rules = [];
let selectedFile = null;

function handleFile(input) {
  const file = input.files[0];
  if (!file) return;
  selectedFile = file;
  document.getElementById('uploadLabel').textContent = '📦 ' + file.name;
  document.getElementById('uploadZone').style.borderColor = 'var(--accent)';
  document.getElementById('uploadZone').style.color = 'var(--accent)';
  document.getElementById('renameBtn').disabled = false;
}

const ruleConfigs = {
  prefix: { label: 'Prefix', fields: [{name:'value', placeholder:'e.g. 2024_'}] },
  suffix: { label: 'Suffix', fields: [{name:'value', placeholder:'e.g. _final'}] },
  replace: { label: 'Find & Replace', fields: [{name:'value', placeholder:'Find'},{name:'replace_with', placeholder:'Replace with'}] },
  lowercase: { label: 'Lowercase', fields: [] },
  uppercase: { label: 'Uppercase', fields: [] },
  spaces_to_underscores: { label: 'Spaces → Underscores', fields: [] },
  remove_special: { label: 'Remove Special Chars', fields: [] },
  numbering: { label: 'Auto-Number', fields: [] },
};

function addRule(type) {
  const id = Date.now();
  const cfg = ruleConfigs[type];
  rules.push({ id, type, value: '', replace_with: '' });

  const div = document.createElement('div');
  div.className = 'rule-row';
  div.id = 'rule_' + id;
  div.innerHTML = `
    <span style="font-size:12px;font-weight:600;color:var(--accent);flex-shrink:0;">${cfg.label}</span>
    ${cfg.fields.map(f => `<input class="input-field" style="margin:0;flex:1;" placeholder="${f.placeholder}" onchange="updateRule(${id},'${f.name}',this.value)">`).join('')}
    <button class="btn-danger-app" style="padding:6px 10px;" onclick="removeRule(${id})"><i class="fas fa-times"></i></button>
  `;
  document.getElementById('rulesList').appendChild(div);
}

function updateRule(id, field, val) {
  const r = rules.find(r => r.id === id);
  if (r) r[field] = val;
}

function removeRule(id) {
  rules = rules.filter(r => r.id !== id);
  document.getElementById('rule_' + id)?.remove();
}

async function processRename() {
  if (!selectedFile) return;
  const btn = document.getElementById('renameBtn');
  btn.innerHTML = '<span class="spinner"></span> Processing...';
  btn.disabled = true;

  const formData = new FormData();
  formData.append('zipfile', selectedFile);
  formData.append('rules', JSON.stringify(rules));

  try {
    const res = await fetch('/rename/process', { method: 'POST', body: formData });
    const data = await res.json();

    if (data.error) {
      alert(data.error);
    } else {
      const list = document.getElementById('previewList');
      list.innerHTML = data.renamed.map(r =>
        `<div class="list-item">
          <i class="fas fa-arrow-right" style="color:var(--accent);font-size:12px;"></i>
          <div style="flex:1;min-width:0;">
            <div style="font-size:11px;color:var(--text-muted);">${r.original}</div>
            <div style="font-size:13px;font-weight:500;">${r.renamed}</div>
          </div>
        </div>`
      ).join('');
      document.getElementById('resultBox').style.display = 'block';
      window.location.href = data.download_url;
    }
  } catch(e) {
    alert('Error: ' + e.message);
  } finally {
    btn.innerHTML = '<i class="fas fa-tags"></i> Apply Rules & Download';
    btn.disabled = false;
  }
}
</script>
{% endblock %}

{% extends "base.html" %}
{% block title %}Cheatsheet Generator{% endblock %}
{% block header_title %}Cheatsheet{% endblock %}
{% set show_back = true %}{% set back_url = '/' %}
{% block header_actions %}
<button class="btn-secondary-app" id="printBtn" onclick="printSheet()" style="display:none;font-size:12px;padding:6px 12px;">
  <i class="fas fa-print"></i> Print
</button>
{% endblock %}

{% block content %}
<div class="section-title">Choose Language / Framework</div>
<div style="display:flex;flex-wrap:wrap;gap:8px;margin-bottom:16px;" id="langChips">
  {% for lang in languages %}
  <button class="chip" onclick="selectLang('{{ lang }}', this)">{{ lang }}</button>
  {% endfor %}
</div>

<label class="field-label">Topic (optional)</label>
<input type="text" id="topicInput" class="input-field" placeholder="e.g. async/await, data structures, OOP...">

<button class="btn-primary-app" id="genBtn" onclick="generate()">
  <i class="fas fa-magic"></i> Generate Cheatsheet
</button>

<div id="resultArea" style="display:none;margin-top:16px;">
  <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:10px;">
    <div class="section-title" style="margin:0;" id="sheetTitle">Cheatsheet</div>
    <div style="display:flex;gap:8px;">
      <button class="btn-secondary-app" onclick="copySheet()" style="font-size:12px;padding:6px 12px;">
        <i class="fas fa-copy"></i>
      </button>
      <button class="btn-secondary-app" onclick="printSheet()" style="font-size:12px;padding:6px 12px;">
        <i class="fas fa-print"></i>
      </button>
    </div>
  </div>
  <div class="result-box md-content" id="sheetContent" style="max-height:none;"></div>
</div>

{% if recent %}
<div class="section-title" style="margin-top:20px;">Recent</div>
{% for sheet in recent %}
<div class="card-app" onclick="loadSheet({{ sheet.id }})" style="cursor:pointer;">
  <div style="display:flex;align-items:center;gap:10px;">
    <div style="width:36px;height:36px;border-radius:10px;background:rgba(34,197,94,0.12);display:flex;align-items:center;justify-content:center;color:#22c55e;">
      <i class="fas fa-code" style="font-size:16px;"></i>
    </div>
    <div>
      <div style="font-size:14px;font-weight:600;">{{ sheet.language }}</div>
      <div style="font-size:11px;color:var(--text-muted);">{{ sheet.created_at.strftime('%b %d, %Y') }}</div>
    </div>
    <i class="fas fa-chevron-right" style="margin-left:auto;color:var(--text-muted);font-size:12px;"></i>
  </div>
</div>
{% endfor %}
{% endif %}
{% endblock %}

{% block scripts %}
<script src="https://cdn.jsdelivr.net/npm/marked/marked.min.js"></script>
<script>
let selectedLang = '';

function selectLang(lang, btn) {
  document.querySelectorAll('#langChips .chip').forEach(c => c.classList.remove('active'));
  btn.classList.add('active');
  selectedLang = lang;
}

async function generate() {
  if (!selectedLang) { alert('Please select a language first'); return; }
  const btn = document.getElementById('genBtn');
  btn.innerHTML = '<span class="spinner"></span> Generating with AI...';
  btn.disabled = true;

  try {
    const res = await fetch('/programcheat/generate', {
      method: 'POST',
      headers: {'Content-Type': 'application/json'},
      body: JSON.stringify({ language: selectedLang, topic: document.getElementById('topicInput').value })
    });
    const data = await res.json();
    if (data.error) {
      alert(data.error);
    } else {
      showSheet(data.language, data.content);
    }
  } catch(e) {
    alert('Error: ' + e.message);
  } finally {
    btn.innerHTML = '<i class="fas fa-magic"></i> Generate Cheatsheet';
    btn.disabled = false;
  }
}

function showSheet(lang, content) {
  document.getElementById('sheetTitle').textContent = lang + ' Cheatsheet';
  document.getElementById('sheetContent').innerHTML = marked.parse(content);
  document.getElementById('resultArea').style.display = 'block';
  document.getElementById('printBtn').style.display = '';
  document.getElementById('resultArea').scrollIntoView({behavior:'smooth'});
}

async function loadSheet(id) {
  const res = await fetch('/programcheat/get/' + id);
  const data = await res.json();
  showSheet(data.language, data.content);
}

function copySheet() {
  const text = document.getElementById('sheetContent').innerText;
  navigator.clipboard.writeText(text).then(() => alert('Copied to clipboard!'));
}

function printSheet() {
  const content = document.getElementById('sheetContent').innerHTML;
  const win = window.open('', '_blank');
  win.document.write(`<html><head><title>Cheatsheet</title>
  <style>body{font-family:monospace;padding:20px;font-size:12px;}code{background:#f0f0f0;padding:2px 6px;border-radius:3px;}pre{background:#f0f0f0;padding:10px;border-radius:4px;}h1,h2,h3{color:#333;}table{border-collapse:collapse;width:100%;}th,td{border:1px solid #ccc;padding:6px;}@media print{body{padding:0;}}</style>
  </head><body>${content}</body></html>`);
  win.document.close();
  win.print();
}
</script>
{% endblock %}

{% extends "base.html" %}
{% block title %}NDA Generator{% endblock %}
{% block header_title %}NDA Generator{% endblock %}
{% set show_back = true %}{% set back_url = '/' %}

{% block content %}
<!-- Steps -->
<div style="display:flex;gap:0;margin-bottom:18px;">
  {% for step, label in [(1,'Details'),(2,'Review'),(3,'Sign')] %}
  <div style="flex:1;text-align:center;">
    <div style="width:28px;height:28px;border-radius:50%;display:flex;align-items:center;justify-content:center;margin:0 auto 4px;font-size:12px;font-weight:700;" id="step{{ step }}Dot"
      style="background:var(--surface2);color:var(--text-muted);">{{ step }}</div>
    <div style="font-size:10px;color:var(--text-muted);" id="step{{ step }}Label">{{ label }}</div>
  </div>
  {% if not loop.last %}
  <div style="flex:0 0 24px;height:1px;background:var(--border);margin-top:14px;"></div>
  {% endif %}
  {% endfor %}
</div>

<!-- Step 1: Details -->
<div id="step1">
  <label class="field-label">Disclosing Party (Party A)</label>
  <input type="text" id="partyA" class="input-field" placeholder="Company or Person Name">

  <label class="field-label">Receiving Party (Party B)</label>
  <input type="text" id="partyB" class="input-field" placeholder="Company or Person Name">

  <label class="field-label">Purpose of Disclosure</label>
  <textarea id="purpose" class="input-field" rows="3" placeholder="e.g. Evaluating a potential business partnership..."></textarea>

  <label class="field-label">Duration</label>
  <select id="duration" class="input-field">
    <option value="1 year">1 Year</option>
    <option value="2 years" selected>2 Years</option>
    <option value="3 years">3 Years</option>
    <option value="5 years">5 Years</option>
    <option value="indefinitely">Indefinitely</option>
  </select>

  <label class="field-label">Jurisdiction</label>
  <input type="text" id="jurisdiction" class="input-field" placeholder="e.g. State of California, USA">

  <button class="btn-primary-app" id="genBtn" onclick="generateNDA()">
    <i class="fas fa-magic"></i> Generate NDA with AI
  </button>
</div>

<!-- Step 2: Review -->
<div id="step2" style="display:none;">
  <div style="display:flex;gap:8px;margin-bottom:12px;">
    <button class="btn-secondary-app" onclick="goStep(1)"><i class="fas fa-chevron-left"></i> Edit</button>
    <button class="btn-secondary-app" onclick="copyNDA()" style="flex:1;"><i class="fas fa-copy"></i> Copy</button>
    <button class="btn-secondary-app" onclick="downloadNDA()"><i class="fas fa-download"></i></button>
  </div>
  <div class="result-box md-content" id="ndaContent" style="max-height:400px;"></div>
  <button class="btn-primary-app" style="margin-top:14px;" onclick="goStep(3)">
    <i class="fas fa-pen-nib"></i> Proceed to Sign
  </button>
</div>

<!-- Step 3: Sign -->
<div id="step3" style="display:none;">
  <div id="sigSection">
    <div class="card-app" style="margin-bottom:12px;">
      <div style="font-size:13px;font-weight:600;margin-bottom:10px;"><i class="fas fa-pen" style="color:var(--accent);margin-right:6px;"></i>Party A Signature</div>
      <canvas id="sigCanvasA" class="sig-pad" width="360" height="120" style="width:100%;"></canvas>
      <div style="display:flex;gap:8px;margin-top:8px;">
        <button class="btn-secondary-app" onclick="clearSig('A')" style="font-size:12px;">Clear</button>
        <button class="btn-secondary-app" onclick="signParty('a')" style="flex:1;font-size:12px;">✓ Sign as Party A</button>
      </div>
      <div id="sigAStatus" style="font-size:12px;color:var(--text-muted);margin-top:6px;"></div>
    </div>

    <div class="card-app" style="margin-bottom:12px;">
      <div style="font-size:13px;font-weight:600;margin-bottom:10px;"><i class="fas fa-pen" style="color:var(--accent2);margin-right:6px;"></i>Party B Signature</div>
      <canvas id="sigCanvasB" class="sig-pad" width="360" height="120" style="width:100%;"></canvas>
      <div style="display:flex;gap:8px;margin-top:8px;">
        <button class="btn-secondary-app" onclick="clearSig('B')" style="font-size:12px;">Clear</button>
        <button class="btn-secondary-app" onclick="signParty('b')" style="flex:1;font-size:12px;">✓ Sign as Party B</button>
      </div>
      <div id="sigBStatus" style="font-size:12px;color:var(--text-muted);margin-top:6px;"></div>
    </div>

    <div id="signedBadge" style="display:none;text-align:center;padding:20px;">
      <div style="font-size:40px;">✅</div>
      <div style="font-size:16px;font-weight:700;color:var(--success);margin-top:8px;">NDA Fully Signed!</div>
      <div style="font-size:12px;color:var(--text-muted);margin-top:4px;" id="signedDate"></div>
    </div>
  </div>

  <button class="btn-secondary-app" onclick="goStep(2)" style="width:100%;margin-top:8px;">
    <i class="fas fa-chevron-left"></i> Back to Review
  </button>
</div>

{% if docs %}
<div class="section-title" style="margin-top:20px;">Saved NDAs</div>
{% for doc in docs %}
<div class="card-app" style="cursor:pointer;">
  <div style="display:flex;align-items:center;gap:10px;">
    <div style="width:36px;height:36px;border-radius:10px;background:rgba(245,158,11,0.12);display:flex;align-items:center;justify-content:center;color:#f59e0b;">
      <i class="fas fa-file-contract"></i>
    </div>
    <div style="flex:1;min-width:0;">
      <div style="font-size:13px;font-weight:600;">{{ doc.party_a }} ↔ {{ doc.party_b }}</div>
      <div style="font-size:11px;color:var(--text-muted);">{{ doc.created_at.strftime('%b %d, %Y') }} · {% if doc.signed_at %}<span style="color:var(--success);">Signed</span>{% else %}Pending{% endif %}</div>
    </div>
  </div>
</div>
{% endfor %}
{% endif %}
{% endblock %}

{% block scripts %}
<script src="https://cdn.jsdelivr.net/npm/marked/marked.min.js"></script>
<script src="https://cdn.jsdelivr.net/npm/signature_pad@4.1.7/dist/signature_pad.umd.min.js"></script>
<script>
let currentDocId = null;
let sigPadA, sigPadB;

document.addEventListener('DOMContentLoaded', () => {
  sigPadA = new SignaturePad(document.getElementById('sigCanvasA'), { backgroundColor:'rgba(255,255,255,1)', penColor:'#1a1a1a' });
  sigPadB = new SignaturePad(document.getElementById('sigCanvasB'), { backgroundColor:'rgba(255,255,255,1)', penColor:'#1a1a1a' });
  setStepActive(1);
});

function setStepActive(n) {
  [1,2,3].forEach(i => {
    const dot = document.getElementById('step'+i+'Dot');
    dot.style.background = i === n ? 'var(--accent)' : i < n ? 'var(--success)' : 'var(--surface2)';
    dot.style.color = i <= n ? '#fff' : 'var(--text-muted)';
  });
}

function goStep(n) {
  document.getElementById('step1').style.display = n===1 ? '' : 'none';
  document.getElementById('step2').style.display = n===2 ? '' : 'none';
  document.getElementById('step3').style.display = n===3 ? '' : 'none';
  setStepActive(n);
}

async function generateNDA() {
  const partyA = document.getElementById('partyA').value.trim();
  const partyB = document.getElementById('partyB').value.trim();
  const purpose = document.getElementById('purpose').value.trim();
  if (!partyA || !partyB || !purpose) { alert('Please fill in all required fields'); return; }

  const btn = document.getElementById('genBtn');
  btn.innerHTML = '<span class="spinner"></span> Generating with AI...';
  btn.disabled = true;

  try {
    const res = await fetch('/ndagen/generate', {
      method: 'POST',
      headers: {'Content-Type': 'application/json'},
      body: JSON.stringify({
        party_a: partyA, party_b: partyB,
        purpose: purpose,
        duration: document.getElementById('duration').value,
        jurisdiction: document.getElementById('jurisdiction').value
      })
    });
    const data = await res.json();
    if (data.error) {
      alert(data.error);
    } else {
      currentDocId = data.id;
      document.getElementById('ndaContent').innerHTML = marked.parse(data.content);
      goStep(2);
    }
  } catch(e) { alert('Error: ' + e.message); }
  finally {
    btn.innerHTML = '<i class="fas fa-magic"></i> Generate NDA with AI';
    btn.disabled = false;
  }
}

function copyNDA() {
  navigator.clipboard.writeText(document.getElementById('ndaContent').innerText).then(() => alert('Copied!'));
}

function downloadNDA() {
  const blob = new Blob([document.getElementById('ndaContent').innerText], {type: 'text/plain'});
  const a = document.createElement('a'); a.href = URL.createObjectURL(blob);
  a.download = 'NDA_' + Date.now() + '.txt'; a.click();
}

function clearSig(party) {
  party === 'A' ? sigPadA.clear() : sigPadB.clear();
}

async function signParty(party) {
  const pad = party === 'a' ? sigPadA : sigPadB;
  if (pad.isEmpty()) { alert('Please draw your signature'); return; }
  if (!currentDocId) { alert('Please generate an NDA first'); return; }

  const sig = pad.toDataURL();
  const res = await fetch(`/ndagen/sign/${currentDocId}`, {
    method: 'POST',
    headers: {'Content-Type': 'application/json'},
    body: JSON.stringify({ party, signature: sig })
  });
  const data = await res.json();
  if (data.success) {
    const statusEl = document.getElementById('sig' + party.toUpperCase() + 'Status');
    statusEl.textContent = '✓ Signed';
    statusEl.style.color = 'var(--success)';
    if (data.fully_signed) {
      document.getElementById('signedBadge').style.display = 'block';
      document.getElementById('signedDate').textContent = 'Signed on ' + new Date().toLocaleDateString();
    }
  }
}
</script>
{% endblock %}

{% extends "base.html" %}
{% block title %}Layout Tester{% endblock %}
{% block header_title %}Layout Tester{% endblock %}
{% set show_back = true %}{% set back_url = '/' %}

{% block content %}
<label class="field-label">Website URL</label>
<div style="display:flex;gap:8px;margin-bottom:14px;">
  <input type="url" id="urlInput" class="input-field" style="margin:0;flex:1;" placeholder="https://example.com">
  <button class="btn-primary-app" style="width:auto;padding:0 16px;" onclick="loadPreview()">
    <i class="fas fa-play"></i>
  </button>
</div>

<div class="section-title">Device</div>
<div style="display:flex;gap:8px;flex-wrap:wrap;margin-bottom:14px;" id="deviceChips">
  {% for d in devices %}
  <button class="chip {% if loop.first %}active{% endif %}"
    onclick="selectDevice({{ d.width }}, {{ d.height }}, '{{ d.name }}', this)"
    data-w="{{ d.width }}" data-h="{{ d.height }}">
    <i class="fas {{ d.icon }}"></i> {{ d.name }}
  </button>
  {% endfor %}
</div>

<div id="customSizeRow" style="display:none;gap:8px;margin-bottom:14px;">
  <input type="number" id="customW" class="input-field" style="margin:0;" placeholder="Width px" value="800">
  <input type="number" id="customH" class="input-field" style="margin:0;" placeholder="Height px" value="600">
</div>

<div id="previewInfo" style="font-size:12px;color:var(--text-muted);text-align:center;margin-bottom:10px;"></div>

<div id="frameWrapper" style="overflow:auto;-webkit-overflow-scrolling:touch;border:1px solid var(--border);border-radius:var(--radius);background:var(--surface2);min-height:200px;display:flex;align-items:center;justify-content:center;">
  <div style="text-align:center;color:var(--text-muted);">
    <i class="fas fa-globe" style="font-size:32px;display:block;margin-bottom:8px;"></i>
    <div style="font-size:13px;">Enter a URL and press play</div>
  </div>
</div>
{% endblock %}

{% block scripts %}
<script>
let curW = {{ devices[0].width }}, curH = {{ devices[0].height }}, curName = '{{ devices[0].name }}';

function selectDevice(w, h, name, btn) {
  document.querySelectorAll('#deviceChips .chip').forEach(c => c.classList.remove('active'));
  btn.classList.add('active');
  curW = w; curH = h; curName = name;
  document.getElementById('customSizeRow').style.display = (name === 'Custom') ? 'flex' : 'none';
  if (document.getElementById('previewInfo').textContent) loadPreview();
}

function loadPreview() {
  let url = document.getElementById('urlInput').value.trim();
  if (!url) return;
  if (!url.startsWith('http')) url = 'https://' + url;

  let w = curW, h = curH;
  if (curName === 'Custom') {
    w = parseInt(document.getElementById('customW').value) || 800;
    h = parseInt(document.getElementById('customH').value) || 600;
  }
  if (!w) w = 1280;

  const wrapper = document.getElementById('frameWrapper');
  const containerW = wrapper.offsetWidth - 2;
  const scale = Math.min(1, containerW / w);
  const scaledH = Math.round((h || 600) * scale);

  document.getElementById('previewInfo').textContent = `${curName}: ${w}×${h} px (scaled to fit)`;

  wrapper.innerHTML = `
    <div style="width:${containerW}px;height:${scaledH}px;overflow:hidden;position:relative;">
      <iframe src="${url}" width="${w}" height="${h || 600}"
        style="transform:scale(${scale});transform-origin:top left;border:none;pointer-events:none;"
        sandbox="allow-same-origin allow-scripts">
      </iframe>
    </div>`;
}

document.getElementById('urlInput').addEventListener('keypress', e => { if (e.key==='Enter') loadPreview(); });
</script>
{% endblock %}

{% extends "base.html" %}
{% block title %}Web Screenshot{% endblock %}
{% block header_title %}Screenshot{% endblock %}
{% set show_back = true %}{% set back_url = '/' %}

{% block content %}
<label class="field-label">Website URL</label>
<input type="url" id="urlInput" class="input-field" placeholder="https://example.com">

<div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-bottom:14px;">
  <div>
    <label class="field-label">Width (px)</label>
    <input type="number" id="widthInput" class="input-field" value="1280" min="320" max="2560">
  </div>
  <div>
    <label class="field-label">Height (px)</label>
    <input type="number" id="heightInput" class="input-field" value="800" min="240" max="2000">
  </div>
</div>

<div style="display:flex;gap:8px;flex-wrap:wrap;margin-bottom:14px;">
  {% for label, w, h in [('Mobile',375,812),('Tablet',768,1024),('Laptop',1280,800),('4K',3840,2160)] %}
  <button class="chip" onclick="setPreset({{ w }},{{ h }})">{{ label }}</button>
  {% endfor %}
</div>

<button class="btn-primary-app" id="captureBtn" onclick="capture()">
  <i class="fas fa-camera"></i> Capture Screenshot
</button>

<div id="resultArea" style="display:none;margin-top:16px;">
  <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:10px;">
    <div class="section-title" style="margin:0;">Result</div>
    <a id="downloadBtn" class="btn-secondary-app" style="font-size:12px;padding:7px 14px;text-decoration:none;">
      <i class="fas fa-download"></i> Download
    </a>
  </div>
  <img id="resultImg" class="screenshot-thumb" style="width:100%;border-radius:12px;" alt="Screenshot">
  <div style="font-size:11px;color:var(--text-muted);text-align:center;margin-top:6px;" id="resultMeta"></div>
</div>

{% if shots %}
<div class="section-title" style="margin-top:20px;">Gallery</div>
<div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;">
  {% for shot in shots %}
  <div style="position:relative;">
    <img src="/static/screenshots/{{ shot.filename }}" class="screenshot-thumb" alt="{{ shot.url }}"
      style="cursor:pointer;" onclick="viewShot('/static/screenshots/{{ shot.filename }}', '{{ shot.url }}')">
    <div style="font-size:10px;color:var(--text-muted);margin-top:4px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">{{ shot.url }}</div>
    <div style="font-size:9px;color:var(--text-muted);">{{ shot.created_at.strftime('%b %d') }}</div>
  </div>
  {% endfor %}
</div>
{% endif %}

<!-- Lightbox -->
<div id="lightbox" style="display:none;position:fixed;inset:0;background:rgba(0,0,0,0.92);z-index:999;flex-direction:column;align-items:center;justify-content:center;padding:20px;">
  <div style="display:flex;justify-content:space-between;width:100%;max-width:430px;margin-bottom:10px;">
    <div id="lbMeta" style="font-size:12px;color:#aaa;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;flex:1;"></div>
    <button onclick="closeLB()" style="background:none;border:none;color:#fff;font-size:20px;cursor:pointer;"><i class="fas fa-times"></i></button>
  </div>
  <img id="lbImg" style="max-width:100%;max-height:80vh;border-radius:8px;" alt="">
  <a id="lbDownload" class="btn-primary-app" style="margin-top:14px;max-width:200px;text-decoration:none;">
    <i class="fas fa-download"></i> Download
  </a>
</div>
{% endblock %}

{% block scripts %}
<script>
function setPreset(w, h) {
  document.getElementById('widthInput').value = w;
  document.getElementById('heightInput').value = h;
}

async function capture() {
  let url = document.getElementById('urlInput').value.trim();
  if (!url) { alert('Enter a URL'); return; }
  const btn = document.getElementById('captureBtn');
  btn.innerHTML = '<span class="spinner"></span> Capturing...';
  btn.disabled = true;

  try {
    const res = await fetch('/webscreen/capture', {
      method: 'POST',
      headers: {'Content-Type': 'application/json'},
      body: JSON.stringify({
        url, width: document.getElementById('widthInput').value,
        height: document.getElementById('heightInput').value
      })
    });
    const data = await res.json();
    if (data.error) {
      alert(data.error);
    } else {
      document.getElementById('resultImg').src = data.url;
      document.getElementById('downloadBtn').href = '/webscreen/download/' + data.filename;
      document.getElementById('downloadBtn').download = data.filename;
      document.getElementById('resultMeta').textContent = url;
      document.getElementById('resultArea').style.display = 'block';
      document.getElementById('resultArea').scrollIntoView({behavior:'smooth'});
    }
  } catch(e) { alert('Error: ' + e.message); }
  finally {
    btn.innerHTML = '<i class="fas fa-camera"></i> Capture Screenshot';
    btn.disabled = false;
  }
}

function viewShot(src, url) {
  document.getElementById('lbImg').src = src;
  document.getElementById('lbMeta').textContent = url;
  document.getElementById('lbDownload').href = src;
  document.getElementById('lbDownload').download = src.split('/').pop();
  document.getElementById('lightbox').style.display = 'flex';
}

function closeLB() { document.getElementById('lightbox').style.display = 'none'; }

document.getElementById('urlInput').addEventListener('keypress', e => { if (e.key==='Enter') capture(); });
</script>
{% endblock %}

