/* ============================================
   DevTools Suite — Web App Stylesheet
   Colors: green, red, yellow, brown, lime
   ============================================ */

*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

body {
  font-family: 'Inter', 'Segoe UI', system-ui, sans-serif;
  background: var(--bg);
  color: var(--text);
  min-height: 100vh;
  line-height: 1.5;
}

a { color: inherit; text-decoration: none; }

/* ---- Scrollbar ---- */
::-webkit-scrollbar { width: 6px; height: 6px; }
::-webkit-scrollbar-track { background: transparent; }
::-webkit-scrollbar-thumb { background: var(--border); border-radius: 3px; }

/* ============ TOP NAV ============ */
.topnav {
  display: flex;
  align-items: center;
  padding: 0 32px;
  height: 60px;
  background: var(--nav-bg);
  border-bottom: 2px solid var(--accent);
  gap: 16px;
  flex-shrink: 0;
  position: sticky;
  top: 0;
  z-index: 100;
}
.topnav-brand {
  display: flex;
  align-items: center;
  gap: 10px;
  font-size: 18px;
  font-weight: 800;
  color: var(--accent);
  letter-spacing: -0.02em;
}
.topnav-brand i { font-size: 22px; }
.topnav-spacer { flex: 1; }
.topnav-link {
  font-size: 13px;
  font-weight: 600;
  color: var(--text-muted);
  padding: 6px 14px;
  border-radius: 6px;
  transition: all 0.15s;
}
.topnav-link:hover { color: var(--accent); background: var(--surface); }
.topnav-badge {
  background: var(--accent);
  color: var(--bg);
  font-size: 11px;
  font-weight: 700;
  padding: 2px 8px;
  border-radius: 20px;
}

/* ============ PAGE WRAPPER ============ */
.page-wrapper {
  max-width: 1400px;
  margin: 0 auto;
  padding: 32px 32px 60px;
}
.page-wrapper.full { max-width: 100%; padding: 24px 32px 60px; }
.page-wrapper.narrow { max-width: 860px; }

/* ============ PAGE HEADER ============ */
.page-header {
  margin-bottom: 32px;
}
.page-header h1 {
  font-size: 32px;
  font-weight: 800;
  color: var(--text);
  letter-spacing: -0.03em;
  line-height: 1.1;
}
.page-header h1 span { color: var(--accent); }
.page-header p {
  margin-top: 8px;
  font-size: 15px;
  color: var(--text-muted);
}
.breadcrumb {
  display: flex;
  align-items: center;
  gap: 8px;
  font-size: 12px;
  color: var(--text-muted);
  margin-bottom: 12px;
}
.breadcrumb a { color: var(--accent); }

/* ============ GRID LAYOUTS ============ */
.grid-2 { display: grid; grid-template-columns: 1fr 1fr; gap: 24px; }
.grid-3 { display: grid; grid-template-columns: repeat(3, 1fr); gap: 20px; }
.grid-4 { display: grid; grid-template-columns: repeat(4, 1fr); gap: 16px; }
.split { display: grid; grid-template-columns: 340px 1fr; gap: 24px; align-items: start; }
.split-wide { display: grid; grid-template-columns: 420px 1fr; gap: 24px; align-items: start; }

@media (max-width: 900px) {
  .grid-2, .grid-3, .grid-4, .split, .split-wide { grid-template-columns: 1fr; }
  .page-wrapper { padding: 20px 16px 40px; }
  .topnav { padding: 0 16px; }
}

/* ============ CARDS ============ */
.card {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: 12px;
  padding: 24px;
}
.card-sm { padding: 16px; border-radius: 10px; }
.card-lg { padding: 32px; }
.card-accent {
  border-color: var(--accent);
  background: var(--surface);
}

/* ============ FORMS ============ */
.field { margin-bottom: 18px; }
.field label {
  display: block;
  font-size: 12px;
  font-weight: 700;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.06em;
  margin-bottom: 7px;
}
input, select, textarea {
  width: 100%;
  background: var(--input-bg);
  border: 1.5px solid var(--border);
  border-radius: 8px;
  padding: 10px 14px;
  color: var(--text);
  font-size: 14px;
  font-family: inherit;
  outline: none;
  transition: border-color 0.2s, box-shadow 0.2s;
}
input:focus, select:focus, textarea:focus {
  border-color: var(--accent);
  box-shadow: 0 0 0 3px var(--accent-glow);
}
input::placeholder, textarea::placeholder { color: var(--text-muted); }
select option { background: var(--surface); color: var(--text); }
textarea { resize: vertical; min-height: 100px; }

/* ============ BUTTONS ============ */
.btn {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 10px 20px;
  border-radius: 8px;
  font-size: 14px;
  font-weight: 600;
  cursor: pointer;
  border: none;
  transition: all 0.15s;
  white-space: nowrap;
}
.btn:active { transform: scale(0.97); }
.btn:disabled { opacity: 0.5; cursor: not-allowed; transform: none; }

.btn-primary {
  background: var(--accent);
  color: var(--btn-text, #000);
}
.btn-primary:hover { filter: brightness(1.1); }

.btn-outline {
  background: transparent;
  color: var(--accent);
  border: 1.5px solid var(--accent);
}
.btn-outline:hover { background: var(--accent); color: var(--btn-text, #000); }

.btn-ghost {
  background: var(--surface);
  color: var(--text-muted);
  border: 1px solid var(--border);
}
.btn-ghost:hover { border-color: var(--accent); color: var(--text); }

.btn-danger {
  background: rgba(239,68,68,0.12);
  color: #ef4444;
  border: 1px solid rgba(239,68,68,0.3);
}
.btn-danger:hover { background: rgba(239,68,68,0.2); }

.btn-lg { padding: 13px 28px; font-size: 15px; }
.btn-sm { padding: 7px 14px; font-size: 12px; }
.btn-icon { padding: 8px 12px; }
.btn-full { width: 100%; justify-content: center; }

/* ============ SECTION TITLES ============ */
.section-label {
  font-size: 11px;
  font-weight: 800;
  color: var(--accent);
  text-transform: uppercase;
  letter-spacing: 0.1em;
  margin-bottom: 12px;
  display: flex;
  align-items: center;
  gap: 8px;
}
.section-label::after { content: ''; flex: 1; height: 1px; background: var(--border); }

/* ============ BADGES / CHIPS ============ */
.badge {
  display: inline-flex;
  align-items: center;
  gap: 5px;
  padding: 4px 10px;
  border-radius: 20px;
  font-size: 11px;
  font-weight: 700;
  border: 1px solid currentColor;
}
.chip {
  display: inline-flex;
  align-items: center;
  gap: 5px;
  padding: 6px 14px;
  border-radius: 20px;
  font-size: 13px;
  font-weight: 500;
  cursor: pointer;
  background: var(--surface);
  border: 1.5px solid var(--border);
  color: var(--text-muted);
  transition: all 0.15s;
}
.chip:hover, .chip.active {
  background: var(--accent);
  color: var(--btn-text, #000);
  border-color: var(--accent);
}
.chip-sm { padding: 4px 10px; font-size: 12px; }

/* ============ ALERTS ============ */
.alert {
  display: flex;
  align-items: flex-start;
  gap: 12px;
  padding: 14px 18px;
  border-radius: 10px;
  font-size: 14px;
  margin-bottom: 20px;
  border: 1px solid;
}
.alert-success { background: rgba(34,197,94,0.08); color: #4ade80; border-color: rgba(34,197,94,0.3); }
.alert-error { background: rgba(239,68,68,0.08); color: #f87171; border-color: rgba(239,68,68,0.3); }
.alert-warning { background: rgba(234,179,8,0.08); color: #fde047; border-color: rgba(234,179,8,0.3); }

/* ============ TABLE ============ */
.table-wrap { overflow-x: auto; border-radius: 10px; border: 1px solid var(--border); }
table { width: 100%; border-collapse: collapse; }
th {
  background: var(--surface);
  padding: 11px 16px;
  text-align: left;
  font-size: 11px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  color: var(--text-muted);
  border-bottom: 1px solid var(--border);
}
td {
  padding: 12px 16px;
  font-size: 13px;
  border-bottom: 1px solid var(--border);
  vertical-align: middle;
}
tr:last-child td { border-bottom: none; }
tr:hover td { background: var(--surface); }

/* ============ STATS ============ */
.stat-row { display: flex; gap: 16px; margin-bottom: 28px; flex-wrap: wrap; }
.stat {
  flex: 1;
  min-width: 120px;
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: 10px;
  padding: 18px 20px;
  border-left: 3px solid var(--accent);
}
.stat-value { font-size: 30px; font-weight: 800; color: var(--accent); line-height: 1; }
.stat-label { font-size: 12px; color: var(--text-muted); margin-top: 4px; font-weight: 600; text-transform: uppercase; }

/* ============ UPLOAD ZONE ============ */
.upload-zone {
  border: 2px dashed var(--border);
  border-radius: 12px;
  padding: 40px 24px;
  text-align: center;
  cursor: pointer;
  transition: all 0.2s;
  color: var(--text-muted);
}
.upload-zone:hover, .upload-zone.drag-over {
  border-color: var(--accent);
  background: var(--accent-glow);
  color: var(--accent);
}
.upload-zone i { font-size: 40px; display: block; margin-bottom: 12px; }
.upload-zone h3 { font-size: 16px; font-weight: 600; margin-bottom: 4px; }
.upload-zone p { font-size: 13px; }

/* ============ SPINNER ============ */
.spinner {
  width: 18px; height: 18px;
  border: 2.5px solid rgba(255,255,255,0.25);
  border-top-color: currentColor;
  border-radius: 50%;
  animation: spin 0.7s linear infinite;
  display: inline-block;
  flex-shrink: 0;
}
@keyframes spin { to { transform: rotate(360deg); } }

/* ============ CODE / RESULT AREA ============ */
.code-box {
  background: var(--code-bg, #0d0d0d);
  border: 1px solid var(--border);
  border-radius: 10px;
  padding: 20px;
  font-family: 'Fira Code', 'Cascadia Code', 'Consolas', monospace;
  font-size: 13px;
  line-height: 1.7;
  overflow: auto;
  white-space: pre-wrap;
  color: var(--text);
}

/* ============ MARKDOWN ============ */
.md h1, .md h2, .md h3 { color: var(--accent); margin: 14px 0 6px; }
.md h1 { font-size: 18px; } .md h2 { font-size: 16px; } .md h3 { font-size: 14px; }
.md p { margin-bottom: 10px; font-size: 14px; }
.md code { background: var(--surface); padding: 2px 7px; border-radius: 4px; font-family: monospace; font-size: 12px; color: var(--accent); }
.md pre { background: var(--code-bg, #0d0d0d); padding: 16px; border-radius: 8px; overflow-x: auto; margin: 10px 0; }
.md pre code { background: none; padding: 0; color: #a3e635; font-size: 13px; }
.md ul, .md ol { padding-left: 20px; margin-bottom: 10px; font-size: 14px; }
.md li { margin-bottom: 4px; }
.md table { width: 100%; border-collapse: collapse; font-size: 13px; margin: 10px 0; }
.md th { background: var(--surface); padding: 8px 12px; border: 1px solid var(--border); text-align: left; }
.md td { padding: 8px 12px; border: 1px solid var(--border); }

/* ============ SIGNATURE PAD ============ */
.sig-container {
  border: 1.5px solid var(--border);
  border-radius: 10px;
  overflow: hidden;
  background: #fff;
}
.sig-container canvas { display: block; width: 100%; touch-action: none; }
.sig-toolbar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 8px 12px;
  background: var(--surface);
  border-top: 1px solid var(--border);
}

/* ============ PROGRESS STEPS ============ */
.steps {
  display: flex;
  align-items: center;
  gap: 0;
  margin-bottom: 32px;
}
.step {
  display: flex;
  align-items: center;
  gap: 10px;
  flex: 1;
}
.step-dot {
  width: 32px; height: 32px;
  border-radius: 50%;
  display: flex; align-items: center; justify-content: center;
  font-size: 13px; font-weight: 700;
  border: 2px solid var(--border);
  background: var(--surface);
  color: var(--text-muted);
  flex-shrink: 0;
  transition: all 0.2s;
}
.step-dot.active { background: var(--accent); border-color: var(--accent); color: #000; }
.step-dot.done { background: #22c55e; border-color: #22c55e; color: #fff; }
.step-info { flex: 1; }
.step-info .step-title { font-size: 13px; font-weight: 600; }
.step-info .step-sub { font-size: 11px; color: var(--text-muted); }
.step-line { flex: 1; height: 2px; background: var(--border); margin: 0 8px; max-width: 40px; }
.step-line.done { background: #22c55e; }

/* ============ DEVICE FRAMES ============ */
.device-frame {
  border: 2px solid var(--border);
  border-radius: 8px;
  background: #000;
  overflow: hidden;
  position: relative;
}
.device-frame iframe {
  border: none;
  display: block;
  transform-origin: top left;
  pointer-events: none;
}

/* ============ SCREENSHOT GRID ============ */
.screenshot-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(240px, 1fr)); gap: 16px; }
.screenshot-card {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: 10px;
  overflow: hidden;
  cursor: pointer;
  transition: transform 0.15s, border-color 0.15s;
}
.screenshot-card:hover { transform: translateY(-2px); border-color: var(--accent); }
.screenshot-card img { width: 100%; aspect-ratio: 16/9; object-fit: cover; display: block; }
.screenshot-card-footer { padding: 10px 12px; }
.screenshot-card-url { font-size: 12px; color: var(--text-muted); white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
.screenshot-card-date { font-size: 11px; color: var(--text-muted); margin-top: 2px; }

/* ============ ADMIN SIDEBAR ============ */
.admin-layout {
  display: grid;
  grid-template-columns: 240px 1fr;
  min-height: calc(100vh - 60px);
}
.admin-sidebar {
  background: var(--surface);
  border-right: 1px solid var(--border);
  padding: 24px 0;
  position: sticky;
  top: 60px;
  height: calc(100vh - 60px);
  overflow-y: auto;
}
.admin-sidebar-section { padding: 0 16px; margin-bottom: 8px; }
.admin-sidebar-label { font-size: 10px; font-weight: 800; text-transform: uppercase; letter-spacing: 0.1em; color: var(--text-muted); padding: 12px 12px 6px; }
.admin-nav-item {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 10px 12px;
  border-radius: 8px;
  font-size: 13px;
  font-weight: 500;
  color: var(--text-muted);
  cursor: pointer;
  transition: all 0.15s;
  margin: 1px 0;
}
.admin-nav-item:hover, .admin-nav-item.active { background: var(--accent-glow); color: var(--accent); }
.admin-nav-item i { width: 18px; text-align: center; }
.admin-content { padding: 32px; }

@media (max-width: 900px) {
  .admin-layout { grid-template-columns: 1fr; }
  .admin-sidebar { position: static; height: auto; }
}

/* ============ HOME PAGE ============ */
.home-hero {
  text-align: center;
  padding: 60px 24px 48px;
}
.home-hero h1 {
  font-size: 52px;
  font-weight: 900;
  letter-spacing: -0.04em;
  line-height: 1.05;
}
.home-hero p { font-size: 18px; color: var(--text-muted); margin-top: 14px; }
.app-cards { display: grid; grid-template-columns: repeat(auto-fill, minmax(280px, 1fr)); gap: 20px; padding: 0 32px 60px; }
.app-card {
  border-radius: 16px;
  padding: 28px 24px;
  text-decoration: none;
  display: flex;
  flex-direction: column;
  gap: 14px;
  border: 1px solid transparent;
  transition: transform 0.15s, box-shadow 0.15s;
  position: relative;
  overflow: hidden;
}
.app-card::before {
  content: '';
  position: absolute;
  inset: 0;
  background: linear-gradient(135deg, rgba(255,255,255,0.05) 0%, transparent 60%);
  pointer-events: none;
}
.app-card:hover { transform: translateY(-4px); box-shadow: 0 12px 40px rgba(0,0,0,0.4); }
.app-card-icon { font-size: 36px; width: 64px; height: 64px; border-radius: 16px; display: flex; align-items: center; justify-content: center; }
.app-card h2 { font-size: 20px; font-weight: 700; }
.app-card p { font-size: 13px; opacity: 0.7; line-height: 1.5; }
.app-card-arrow { margin-top: auto; font-size: 20px; opacity: 0.6; align-self: flex-end; }

/* ============ RULE BUILDER ============ */
.rule-item {
  display: flex;
  align-items: center;
  gap: 10px;
  background: var(--surface);
  border: 1px solid var(--border);
  border-left: 3px solid var(--accent);
  border-radius: 8px;
  padding: 12px 14px;
  margin-bottom: 8px;
}
.rule-label { font-size: 12px; font-weight: 700; color: var(--accent); white-space: nowrap; min-width: 90px; }
.rule-inputs { display: flex; gap: 8px; flex: 1; }
.rule-inputs input { margin: 0; }

/* ============ TOOLBAR ============ */
.toolbar {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 12px 20px;
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: 10px;
  margin-bottom: 20px;
  flex-wrap: wrap;
}

